var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……이제 됐어요. 더 이상 낭비할 시간 없습니다.","JPN":"……もういいですわ。これ以上時間を無駄遣いするわけにはいきません。","ENG":"...Enough with this. I do not wish to waste any more time.","TWN":"……現在可以了，我沒有時間可以浪費了。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델의 위치나 말하세요. 당신이라면 알고 있을 거라더군요.","JPN":"エデルの位置を教えてください。あなたなら知っていると聞きました。","ENG":"Tell me where Edel is. I heard you will know her whereabouts.","TWN":"請告訴我艾瑟兒的位置。你一定知道吧。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"물론 말씀드릴 수 있습니다.","JPN":"もちろんお教えできます。","ENG":"Yes, I do. And I can tell you.","TWN":"當然，我可以告訴你。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하지만 그 전에, 한 가지 충고해 드리죠.","JPN":"ですがその前に、一つだけ忠告しましょう。","ENG":"But first, please allow me to offer you some advice.","TWN":"只是在那之前，我要給你一個忠告。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"얘기해 보세요. 받아들일지는 들은 다음에 결정하겠습니다.","JPN":"どうぞ。受け入れるかどうかは、聞いてから決めますわ。","ENG":"Continue. I will decide whether to heed your advice after I hear it.","TWN":"你說說看。聽完之後我再決定是否接受。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회장님의 선의를 믿으십시오.","JPN":"学会長の善意を信頼してください。","ENG":"Trust the President's good intentions.","TWN":"請相信學會長的善意。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"선의라고요?","JPN":"善意ですって？","ENG":"Good intentions?","TWN":"善意？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"회동이 끝난 뒤 안정을 위해 휴가를 떠나셨죠. 기억하십니까?","JPN":"会合が終わった後、安静のために休暇を取られましたね。覚えていますか？","ENG":"You went on vacation after the meeting to unwind. Do you recall?","TWN":"會議結束後，你為了放鬆去休假了。你還記得吧？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……네. 기억나요. 리벳이 골라 준 의상을 입고 무대에 서느라 고생했죠.","JPN":"……はい。覚えています。リベットが選んでくれた衣装を着てステージに立つのに苦労しました。","ENG":"...Yes. I remember struggling on stage in the dress Rivet had chosen for me.","TWN":"……是，我記得。穿著里維給我挑的衣服站在舞台上，我還吃了不少苦頭。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그 곳에서 맥크레디 양은 공교롭게도 마왕의 사도와 조우하셨습니다.","JPN":"そこでマクレディーさんはあいにく、魔王の使徒と遭遇してしまいました。","ENG":"There, you coincidentally encountered the Demon Lord's Apostle.","TWN":"在那裡，麥克蕾蒂碰巧遇到了魔王的使徒。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"꼭두각시처럼 조종당하다 몸 속에 있던 마지막 한 방울의 힘까지 빼앗기시고 말았죠.","JPN":"操り人形のように操縦され、体の中に残っていた最後の力まで奪われてしまったのです。","ENG":"You were manipulated like a puppet, and every ounce of strength was taken from you.","TWN":"你像傀儡一樣被操控，被奪走了身體裡的最後一絲力量。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인형의 주인이 저지른 짓이었지. 결과적으로는 자충수였지만.","JPN":"人形の持ち主の仕業だったな。結果的には自滅して終わったが。","ENG":"The Puppet Master was behind it. But it was ultimately a blunder on her part.","TWN":"那事是人偶的主人幹的。不過最後它自食惡果了。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님도…… 그 때 일을 알고 계셨나요?","JPN":"社長も……その時のことをご存じだったのですか？","ENG":"Boss... Did you also know about this?","TWN":"老闆……也知道當時的事嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 불완전한 가아그셰블라가 본체를 현현했을 정도이니 말일세.","JPN":"ああ。不完全なガアグシェブラが本体を現したくらいだったからね。","ENG":"Yes. It was enough for an imperfect embodiment of Gha'agsheblah to manifest.","TWN":"是的。不完整的加瓦格夫拉甚至還顯現出了本體。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"역시 지켜보고 계셨군요.","JPN":"やはり見ていらしたのですね。","ENG":"I knew you were watching it.","TWN":"你果然在看著呢。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"언젠가 당신과 마주앉아 담소를 나눌 날을 기다리고 있었습니다.","JPN":"あなたと向かい合い、なごやかに会話できる日をずっと待ち望んでいました。","ENG":"I have been waiting for a day like this to sit down and have a chat with you.","TWN":"我等著能和你面對面地坐著聊天的那一天。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이 나이에 황홀경이라는 것을 겪을 줄은 몰랐군요.","JPN":"この年になって恍惚の境地というものを経験するとは。","ENG":"I never imagined I'd be experiencing something called rapture at this age.","TWN":"沒想到這個年紀的我還會經歷這種激動人心的時刻。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"당신과 대화하고 있다는 사실을 자각하는 매순간마다…… 전율마저 느껴집니다.","JPN":"あなたと話していることを自覚するたびに……戦慄さえ覚えてしまいます。","ENG":"Every time I realize that I am talking to you... shivers run down my spine.","TWN":"意識到我正在跟你交談的每個瞬間……我都能感受到顫慄。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};